import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is a BTU?", a: "BTU stands for British Thermal Unit. It is the amount of energy needed to raise the temperature of one pound of water by one degree Fahrenheit. In HVAC, BTU/hr measures the cooling or heating capacity of an air conditioner or heater." },
  { q: "How many BTUs do I need per square foot?", a: "A general rule is 20 BTU per square foot of living space. However, ceiling height, climate, insulation, and sun exposure all affect the actual requirement. Rooms with high ceilings or poor insulation may need 25-30 BTU/sqft." },
  { q: "How many BTUs does a 2000 sq ft home need?", a: "A 2,000 sq ft home typically needs 40,000-60,000 BTU for cooling. This varies based on climate zone, insulation quality, and ceiling height. Always consult an HVAC professional for precise sizing." },
  { q: "What happens if an AC unit is too big or too small?", a: "An oversized unit will short-cycle (turn on and off too quickly), failing to dehumidify the air and wasting energy. An undersized unit will run constantly without adequately cooling the space. Proper sizing is critical for efficiency and comfort." },
  { q: "What is a 'ton' of cooling in HVAC?", a: "One ton of cooling = 12,000 BTU/hr. This term comes from the amount of heat needed to melt one ton of ice in 24 hours. A 3-ton AC unit provides 36,000 BTU/hr of cooling capacity." },
  { q: "How does insulation affect BTU requirements?", a: "Well-insulated spaces require 20-30% fewer BTUs to maintain temperature because less heat is transferred through walls, windows, and ceilings. Upgrading insulation often reduces HVAC sizing requirements significantly." },
  { q: "Should I buy a window AC or a mini-split for a single room?", a: "For rooms up to 400 sq ft, a window AC is typically more cost-effective ($100-$400). Mini-splits ($700-$2,000+) are quieter, more efficient, more aesthetically pleasing, and work in rooms without suitable windows. Both require proper BTU sizing to function efficiently." },
];

export default function BTUCalculator() {
  const [area, setArea] = useState(500);
  const [ceilingHeight, setCeilingHeight] = useState(8);
  const [insulation, setInsulation] = useState<"poor" | "average" | "good">("average");
  const [climate, setClimate] = useState<"mild" | "moderate" | "extreme">("moderate");
  const [occupants, setOccupants] = useState(2);
  const [sunExposure, setSunExposure] = useState<"low" | "medium" | "high">("medium");

  const insMap = { poor: 1.3, average: 1.0, good: 0.8 };
  const climateMap = { mild: 0.85, moderate: 1.0, extreme: 1.2 };
  const sunMap = { low: 0.9, medium: 1.0, high: 1.1 };

  const baseBtu = area * 20;
  const heightAdj = ceilingHeight > 8 ? 1 + (ceilingHeight - 8) * 0.05 : 1;
  const btu = baseBtu * insMap[insulation] * climateMap[climate] * sunMap[sunExposure] * heightAdj + occupants * 600;
  const tons = btu / 12000;

  return (
    <>
      <SEOHead
        title="Free BTU Calculator Online - Calculate Heating and Cooling BTUs Instantly | CalcHive"
        description="Free online BTU calculator. Calculate exactly how many BTUs you need to heat or cool any room based on size and conditions instantly. 100% free for everyone, no signup required."
        canonical="/btu-calculator"
        keywords="free BTU calculator, BTU calculator online free, heating cooling BTU calculator free, room BTU calculator free, air conditioner BTU calculator free"
        category="Construction Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-stone-600 dark:text-stone-400 bg-stone-100 dark:bg-stone-800/50 px-3 py-1 rounded-full mb-4 inline-block">Housing</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free BTU Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free BTU calculator to estimate heating and cooling BTUs for any room based on size and conditions. This BTU calculator online free also works as a heating cooling BTU calculator free, room BTU calculator free, and air conditioner BTU calculator free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <SliderInput id="area" label="Room Area (sq ft)" value={area} min={100} max={5000} step={50} onChange={setArea} format={v => `${v.toLocaleString()} sq ft`} testId="input-area" />
            <SliderInput id="ceiling" label="Ceiling Height (ft)" value={ceilingHeight} min={7} max={20} step={0.5} onChange={setCeilingHeight} format={v => `${v} ft`} testId="input-ceiling" />
            <SliderInput id="occupants" label="Number of Occupants" value={occupants} min={1} max={20} step={1} onChange={setOccupants} format={v => `${v} people`} testId="input-occupants" />
            {[
              { label: "Insulation Quality", val: insulation, set: setInsulation, opts: [["poor", "Poor"], ["average", "Average"], ["good", "Good"]] as const },
              { label: "Climate", val: climate, set: setClimate, opts: [["mild", "Mild"], ["moderate", "Moderate"], ["extreme", "Extreme"]] as const },
              { label: "Sun Exposure", val: sunExposure, set: setSunExposure, opts: [["low", "Low"], ["medium", "Medium"], ["high", "High"]] as const },
            ].map(({ label, val, set, opts }) => (
              <div key={label}>
                <label className="text-sm font-semibold text-foreground mb-2 block">{label}</label>
                <div className="flex gap-2">
                  {opts.map(([v, l]) => <button key={v} onClick={() => (set as (x: typeof v) => void)(v)} className={`flex-1 py-2 rounded-xl text-sm font-semibold border transition-all ${val === v ? "bg-stone-600 text-white border-stone-600" : "bg-card text-muted-foreground border-border hover:border-stone-400"}`}>{l}</button>)}
                </div>
              </div>
            ))}
          </div>
          <motion.div key={`${area}-${ceilingHeight}-${insulation}-${climate}-${occupants}-${sunExposure}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-stone-600 to-stone-800 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Recommended BTU</p>
              <p className="text-5xl font-black text-white tracking-tight" data-testid="result-btu">{Math.round(btu).toLocaleString()}</p>
              <p className="text-white/70 text-sm mt-1">BTU/hr needed</p>
            </div>
            <div className="grid grid-cols-2 gap-3">
              {[{ label: "Tons of Cooling", value: tons.toFixed(1) }, { label: "BTU per Sq Ft", value: (btu / area).toFixed(1) }].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-lg font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate BTUs Needed for Any Room for Free</h2>
          <p className="text-muted-foreground leading-relaxed">The basic rule of 20 BTU per square foot is a starting point, but accurate sizing requires adjusting for several factors that affect heat gain and loss in your specific space.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Base BTU = Area (sq ft)  x  20</p>
            <p>Height Adjustment = 1 + (ceiling height - 8)  x  0.05 (if above 8 ft)</p>
            <p>Occupant Load = Number of People  x  600 BTU</p>
            <p>Final BTU = Base  x  Height Adj  x  Insulation Factor  x  Climate Factor  x  Sun Factor + Occupant Load</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How Room Size and Conditions Affect BTU Requirements</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Room Size", "Room Type", "BTU Needed", "AC Tonnage"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["100-150 sq ft", "Small bedroom", "5,000 BTU", "0.4 tons"],
                  ["150-250 sq ft", "Bedroom", "6,000 BTU", "0.5 tons"],
                  ["250-350 sq ft", "Large bedroom", "7,000 BTU", "0.6 tons"],
                  ["350-550 sq ft", "Studio / living room", "10,000 BTU", "0.8 tons"],
                  ["550-700 sq ft", "Large living room", "12,000 BTU", "1 ton"],
                  ["700-1,000 sq ft", "Open floor plan", "18,000 BTU", "1.5 tons"],
                  ["1,000-1,500 sq ft", "Small home", "24,000 BTU", "2 tons"],
                  ["1,500-2,000 sq ft", "Average home", "30,000 BTU", "2.5 tons"],
                  ["2,000-2,500 sq ft", "Large home", "36,000 BTU", "3 tons"],
                ].map(([size, type, btuNeeded, tons]) => (
                  <tr key={size} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{size}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{type}</td>
                    <td className="py-2.5 px-4 text-stone-600 dark:text-stone-400 font-medium">{btuNeeded}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{tons}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Heating and Cooling BTU Tool for Everyone</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Factor", "Condition", "Adjustment"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Ceiling height", "Above 8 ft", "+5% per additional foot"],
                  ["Insulation", "Poor (older home, single-pane windows)", "+30% to base BTU"],
                  ["Insulation", "Good (new construction, double-pane windows)", "- from base BTU"],
                  ["Climate", "Hot/humid (Southeast US, Southwest)", "+20% to base BTU"],
                  ["Climate", "Mild (Pacific Northwest, mountain regions)", "- from base BTU"],
                  ["Sun exposure", "South/west-facing, lots of windows", "+10% to base BTU"],
                  ["Occupants", "Each additional person beyond 2", "+600 BTU"],
                  ["Kitchen", "Room contains cooking appliances", "+4,000 BTU"],
                ].map(([factor, condition, adjustment]) => (
                  <tr key={`${factor}-${condition}`} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{factor}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{condition}</td>
                    <td className="py-2.5 px-4 text-stone-600 dark:text-stone-400 font-medium">{adjustment}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/btu-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


